contracts/auction.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

interface IERC20 {
    function transferFrom(
        address from,
        address to,
        uint256 amount
    ) external returns (bool);

    function transfer(
        address to,
        uint256 amount
    ) external returns (bool);
}

contract Auction {

    uint256 constant DURATION = 5 minutes;

    struct Item {
        string name;
        address seller;
        address highestBidder;
        uint256 highestBid;
        uint256 endTime;
        bool ended;
    }

    IERC20 public immutable token;

    Item[] public items;

    event ItemListed(
        uint256 indexed itemId,
        string name,
        address indexed seller
    );

    event NewBid(
        uint256 indexed itemId,
        address indexed bidder,
        uint256 amount
    );

    event AuctionEnded(
        uint256 indexed itemId,
        address winner,
        uint256 amount
    );

    constructor(address _token) {
        token = IERC20(_token);
    }

    // -------------------------------------------------
    // LIST ITEM
    // -------------------------------------------------

    function listItem(string calldata _name) external {

        items.push(
            Item({
                name: _name,
                seller: msg.sender,
                highestBidder: address(0),
                highestBid: 0,
                endTime: block.timestamp + DURATION,
                ended: false
            })
        );

        emit ItemListed(
            items.length - 1,
            _name,
            msg.sender
        );
    }

    // -------------------------------------------------
    // BID WITH ETH
    // -------------------------------------------------

    function bidETH(uint256 _itemId) external payable {

        Item storage item = items[_itemId];

        require(!item.ended, "Auction ended");

        require(
            block.timestamp < item.endTime,
            "Time over"
        );

        require(
            msg.value > item.highestBid,
            "Low bid"
        );

        // refund previous bidder
        if (item.highestBidder != address(0)) {

            (bool success, ) = payable(
                item.highestBidder
            ).call{value: item.highestBid}("");

            require(success, "Refund failed");
        }

        item.highestBidder = msg.sender;
        item.highestBid = msg.value;

        emit NewBid(
            _itemId,
            msg.sender,
            msg.value
        );
    }

    // -------------------------------------------------
    // BID WITH ERC20
    // -------------------------------------------------

    function bidERC20(
        uint256 _itemId,
        uint256 _amount
    ) external {

        Item storage item = items[_itemId];

        require(!item.ended, "Auction ended");

        require(
            block.timestamp < item.endTime,
            "Time over"
        );

        require(
            _amount > item.highestBid,
            "Low bid"
        );

        // take token from bidder
        bool success = token.transferFrom(
            msg.sender,
            address(this),
            _amount
        );

        require(success, "Transfer failed");

        // refund previous bidder
        if (item.highestBidder != address(0)) {

            token.transfer(
                item.highestBidder,
                item.highestBid
            );
        }

        item.highestBidder = msg.sender;
        item.highestBid = _amount;

        emit NewBid(
            _itemId,
            msg.sender,
            _amount
        );
    }

    // -------------------------------------------------
    // FINALIZE AUCTION
    // -------------------------------------------------

    function finalizeAuction(uint256 _itemId) external {

        Item storage item = items[_itemId];

        require(!item.ended, "Already ended");

        require(
            block.timestamp >= item.endTime,
            "Auction still active"
        );

        item.ended = true;

        // send ETH to seller
        if (item.highestBid > 0) {

            (bool success, ) = payable(
                item.seller
            ).call{value: item.highestBid}("");

            require(success, "Payment failed");
        }

        emit AuctionEnded(
            _itemId,
            item.highestBidder,
            item.highestBid
        );
    }

    // -------------------------------------------------
    // VIEW FUNCTIONS
    // -------------------------------------------------

    function getAllItems()
        external
        view
        returns (Item[] memory)
    {
        return items;
    }

    function getWinner(
        uint256 _itemId
    )
        external
        view
        returns (address)
    {
        return items[_itemId].highestBidder;
    }

    function totalItems()
        external
        view
        returns (uint256)
    {
        return items.length;
    }
}

contracts/Lock.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.28;

// Uncomment this line to use console.log
// import "hardhat/console.sol";

contract Lock {
    uint public unlockTime;
    address payable public owner;

    event Withdrawal(uint amount, uint when);

    constructor(uint _unlockTime) payable {
        require(
            block.timestamp < _unlockTime,
            "Unlock time should be in the future"
        );

        unlockTime = _unlockTime;
        owner = payable(msg.sender);
    }


    function withdraw() public {
        // Uncomment this line, and the import of "hardhat/console.sol", to print a log in your terminal
        // console.log("Unlock time is %o and block timestamp is %o", unlockTime, block.timestamp);

        require(block.timestamp >= unlockTime, "You can't withdraw yet");
        require(msg.sender == owner, "You aren't the owner");

        emit Withdrawal(address(this).balance, block.timestamp);

        owner.transfer(address(this).balance);
    }
}

contracts/MockERC20.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

contract MockERC20 {
    string public name = "MockToken";
    string public symbol = "MTK";
    uint8 public decimals = 18;
    uint256 public totalSupply;

    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    constructor(uint256 initialSupply) {
        mint(msg.sender, initialSupply);
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        require(balanceOf[msg.sender] >= amount, "Insufficient balance");
        balanceOf[msg.sender] -= amount;
        balanceOf[to] += amount;
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowance[msg.sender][spender] = amount;
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        require(allowance[from][msg.sender] >= amount, "Insufficient allowance");
        require(balanceOf[from] >= amount, "Insufficient balance");
        allowance[from][msg.sender] -= amount;
        balanceOf[from] -= amount;
        balanceOf[to] += amount;
        return true;
    }

    function mint(address to, uint256 amount) public {
        balanceOf[to] += amount;
        totalSupply += amount;
    }
}

